import React, { useState, useEffect } from "react";
import "../styles/booking.css";

export default function Booking({ rooms = [] }) {
  // initialize with empty room_id so prop-driven default works reliably
  const [form, setForm] = useState({
    name: "",
    email: "",
    phone: "",
    room_id: "",
    adults: 1,
    children: 0,
    checkin: "",
    checkout: "",
    notes: "",
  });

  const [submitting, setSubmitting] = useState(false);
  const [message, setMessage] = useState(null); // { type: 'success'|'error', text: '' }

  // API base (use REACT_APP_API_URL if provided)
  const API_BASE = process.env.REACT_APP_API_URL || "http://127.0.0.1:8000";

  // When rooms prop becomes available, set default room_id if not set
  useEffect(() => {
    if ((!form.room_id || form.room_id === "") && rooms.length > 0) {
      const first = rooms[0].id ?? rooms[0].room_id ?? "";
      if (first !== "") {
        setForm((f) => ({ ...f, room_id: String(first) }));
      }
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [rooms]);

  // basic client-side validation
  const validate = () => {
    const { name, email, checkin, checkout, adults } = form;
    if (!name.trim()) return "Please enter your name.";
    if (!email.trim() || !/^\S+@\S+\.\S+$/.test(email)) return "Please enter a valid email.";
    if (!checkin) return "Please choose a check-in date.";
    if (!checkout) return "Please choose a check-out date.";
    if (new Date(checkout) <= new Date(checkin)) return "Check-out must be after check-in.";
    if (Number(adults) < 1) return "Please select number of adults.";
    return null;
  };

  const onChange = (e) => {
    const { name, value, type } = e.target;
    // keep form fields as strings except we normalize numbers before submit
    setForm((f) => ({ ...f, [name]: value }));
  };

  const submitHandler = async (e) => {
    e.preventDefault();
    setMessage(null);

    const err = validate();
    if (err) {
      setMessage({ type: "error", text: err });
      return;
    }

    setSubmitting(true);

    try {
      // prepare payload with correct types
      const payload = {
        name: form.name.trim(),
        email: form.email.trim(),
        phone: form.phone.trim(),
        adults: Number(form.adults || 0),
        children: Number(form.children || 0),
        checkin: form.checkin,
        checkout: form.checkout,
        notes: form.notes ? form.notes.trim() : "",
      };

      // include room if available (backend may expect 'room' foreign key)
      if (form.room_id) {
        // send as integer
        payload.room = Number(form.room_id);
      }

      const resp = await fetch(`${API_BASE}/api/reservations/`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!resp.ok) {
        const errBody = await resp.json().catch(() => null);
        // try to extract useful message
        const serverMessage =
          errBody?.detail ||
          (typeof errBody === "object" ? JSON.stringify(errBody) : null) ||
          `Server error (${resp.status})`;
        throw new Error(serverMessage);
      }

      const data = await resp.json();
      setMessage({
        type: "success",
        text:
          "Reservation successful! " +
          (data.id ? `Reference ID: ${data.id}` : data.reference ? `Ref: ${data.reference}` : ""),
      });

      // reset form to defaults
      setForm({
        name: "",
        email: "",
        phone: "",
        room_id: rooms.length > 0 ? String(rooms[0].id ?? rooms[0].room_id ?? "") : "",
        adults: 1,
        children: 0,
        checkin: "",
        checkout: "",
        notes: "",
      });
    } catch (err) {
      setMessage({ type: "error", text: err.message || "Failed to submit reservation." });
    } finally {
      setSubmitting(false);
    }
  };

  return (
    <div className="booking-wrap" aria-live="polite">
      <h2>Make a Reservation</h2>

      {message && (
        <div className={`notify ${message.type === "success" ? "ok" : "err"}`} role="status">
          {message.text}
        </div>
      )}

      <form className="booking-form" onSubmit={submitHandler} noValidate>
        <div className="row">
          <label>
            Full name
            <input
              name="name"
              value={form.name}
              onChange={onChange}
              placeholder="Your full name"
              required
              aria-required="true"
            />
          </label>

          <label>
            Email
            <input
              name="email"
              type="email"
              value={form.email}
              onChange={onChange}
              placeholder="you@example.com"
              required
            />
          </label>
        </div>

        <div className="row">
          <label>
            Phone
            <input name="phone" value={form.phone} onChange={onChange} placeholder="+91 9xxxxxxxxx" />
          </label>

          <label>
            Room
            <select name="room_id" value={form.room_id} onChange={onChange}>
              {rooms.length > 0 ? (
                rooms.map((r) => {
                  const id = r.id ?? r.room_id ?? "";
                  return (
                    <option key={id} value={String(id)}>
                      {r.room_name ?? r.name ?? `Room ${id}`} — ₹{Number(r.price ?? r.rate ?? 0).toFixed(2)}
                    </option>
                  );
                })
              ) : (
                <option value="">(No room list)</option>
              )}
            </select>
          </label>
        </div>

        <div className="row">
          <label>
            Check-in
            <input name="checkin" type="date" value={form.checkin} onChange={onChange} required />
          </label>

          <label>
            Check-out
            <input name="checkout" type="date" value={form.checkout} onChange={onChange} required />
          </label>
        </div>

        <div className="row">
          <label>
            Adults
            <input
              name="adults"
              type="number"
              min="1"
              value={form.adults}
              onChange={onChange}
              required
              aria-label="Number of adults"
            />
          </label>

          <label>
            Children
            <input
              name="children"
              type="number"
              min="0"
              value={form.children}
              onChange={onChange}
              aria-label="Number of children"
            />
          </label>
        </div>

        <label>
          Notes (optional)
          <textarea
            name="notes"
            value={form.notes}
            onChange={onChange}
            placeholder="Any requests (late check-in, food preferences)"
          />
        </label>

        <div className="form-actions">
          <button type="submit" className="btn" disabled={submitting}>
            {submitting ? "Submitting…" : "Book Now"}
          </button>
        </div>
      </form>
    </div>
  );
}
